select reserve_id, start_date, end_date, audit_status
from sys_reservation
where lab_id = #{labId}
  and audit_status IN (0, 1)
  and start_date < #{endDate}
  and end_date > #{startDate}

select reserve_id, start_date, end_date, audit_status
from sys_reservation
where lab_id = #{labId}
  and audit_status IN (0, 1)
  and reserve_id != #{reserveId}
  and start_date < #{endDate}
  and end_date > #{startDate}


where r.user_id = #{userId}

    AND l.lab_name like concat('%', #{labName}, '%')


    AND l.building = #{building}


    AND r.start_date >= #{startTime}


    AND r.end_date <= #{endTime}


    AND r.audit_status = #{auditStatus}

order by r.create_time desc

